module top_module(
    input i_clk,
    input i_reset,
    input i_start,
    input [7:0] i_duration,
    output reg o_pulse
);reg [7:0] pulse_countdown;

    always @(posedge i_clk or posedge i_reset) begin
        if (i_reset) begin
            pulse_countdown <= 0;
            o_pulse <= 0;
        end else if (i_start) begin
            pulse_countdown <= i_duration;
            o_pulse <= 1;
        end else if (pulse_countdown > 0) begin
            pulse_countdown <= pulse_countdown - 1;
            o_pulse <= 1;
        end else begin
            o_pulse <= 0;
        end
    end

endmodule
